// // This module selects between two 8-bit inputs based on the sel signal. When sel is 0, bus1 reflects data1, and when sel is 1, bus1 reflects data0.
module top_module(
    input wire sel,
    input wire [7:0] data0,
    input wire [7:0] data1,
    output wire [7:0] bus1
    );assign bus1 = sel?data1:data0;
endmodule
